class Solution:
    def numsSameConsecDiff(self, n: int, k: int) -> List[int]:
        def dfs(num, length):
            if length == n:
                res.append(num)
                return
            last_digit = num % 10
            for next_digit in [last_digit + k, last_digit - k]:
                if 0 <= next_digit <= 9:
                    dfs(num * 10 + next_digit, length + 1)

        res = []
        for i in range(1, 10):
            dfs(i, 1)
        return res
